export const getSearchContentUrl = (params: SearchContentParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : value.toString())
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/search?${stringifiedParams}` : `/api/search`
}

/**
 * @summary Search across topics, definitions, and formulas
 */
export const searchContent = async (params: SearchContentParams, options?: RequestInit): Promise<SearchResults> => {

  return customFetch<SearchResults>(getSearchContentUrl(params),
  {
    ...options,
    method: 'GET'


  }
);}





export const getSearchContentQueryKey = (params?: SearchContentParams,) => {
    return [
    `/api/search`, ...(params ? [params] : [])
    ] as const;
    }


export const getSearchContentQueryOptions = <TData = Awaited<ReturnType<typeof searchContent>>, TError = ErrorType<unknown>>(params: SearchContentParams, options?: { query?:UseQueryOptions<Awaited<ReturnType<typeof searchContent>>, TError, TData>, request?: SecondParameter<typeof customFetch>}
) => {

const {query: queryOptions, request: requestOptions} = options ?? {};

  const queryKey =  queryOptions?.queryKey ?? getSearchContentQueryKey(params);



    const queryFn: QueryFunction<Awaited<ReturnType<typeof searchContent>>> = ({ signal }) => searchContent(params, { signal, ...requestOptions });





   return  { queryKey, queryFn, ...queryOptions} as UseQueryOptions<Awaited<ReturnType<typeof searchContent>>, TError, TData> & { queryKey: QueryKey }
}

